mapper.insert:
insert into user_update_record (uprId, userId, storeId, 
  oldValidityDate, newValidityDate, createdDate
  )
values (#{uprId,jdbcType=BIGINT}, #{userId,jdbcType=BIGINT}, #{storeId,jdbcType=BIGINT}, 
  #{oldValidityDate,jdbcType=TIMESTAMP}, #{newValidityDate,jdbcType=TIMESTAMP}, #{createdDate,jdbcType=TIMESTAMP}
  )

mapper.select:
select ur.uprId, date_format(ur.oldValidityDate, '%Y-%m-%d') as oldValidityDate, date_format(ur.newValidityDate, '%Y-%m-%d') as newValidityDate, ur.createdDate, ss.username, u.nickname,u.phone, s.storeName from user_update_record ur INNER JOIN user_info u ON u.userId=ur.userId INNER JOIN store s ON s.storeId = ur.storeId INNER JOIN sys_user ss ON ss.user_id = ur.sysUserId
AND ur.storeId=#{storeId}
AND ur.storeId in (${storeIds})
AND u.phone like concat('%',#{phone},'%')
AND u.nickname like concat('%',#{nickname},'%')
AND s.storeName like concat('%',#{storeName},'%')
AND ur.createdDate >= #{startTime}
AND ur.createdDate <= #{endTime}
ORDER BY ur.createdDate DESC
limit #{offset}, #{limit}

select COUNT(*) from user_update_record ur
  INNER JOIN user_info u ON u.userId=ur.userId
  INNER JOIN store s ON s.storeId = ur.storeId
  
      
          AND ur.storeId=#{storeId}
      
      
          AND ur.storeId in (${storeIds})
      
      
          AND u.phone like concat('%',#{phone},'%')
      
      
          AND u.nickname like concat('%',#{nickname},'%')
      
      
          AND s.storeName like concat('%',#{storeName},'%')
                  
      
          AND ur.createdDate >= #{startTime}
      
      
          AND ur.createdDate <= #{endTime}
